sys_script_client.script:
/**
 * onChange Retrieve and populate candidate information into Checkin form fields
 * 
 * @author GEM/Quynhttn - 14.05.2026
 * @param {GlideFormControl} control 
 * @param {string} oldValue
 * @param {string} newValue
 * @param {boolean} isLoading
 * @param {boolean} isTemplate
 * @returns {none}
 */
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   // Stop script when form is loading or candidate field is empty
   if (isLoading || newValue === '') {
      return;
   }

   // Call Script Include to retrieve candidate information
   var gaCheckin = new GlideAjax('TAMUtils');
   gaCheckin.addParam('sysparm_name', 'getTableInfomation');
   gaCheckin.addParam('sysparm_table_name', 'x_1763182_talent_0_candidate');
   gaCheckin.addParam('sysparm_field_return', 'u_email,u_username,u_phone_number');
   gaCheckin.addParam('sysparm_record_id', newValue);
   gaCheckin.getXMLAnswer(poplulateCandidateInformation);
}

/**
 * poplulateCandidateInformation Populate candidate information into Checkin form fields
 *
 * @author GEM/Quynhttn - 14.05.2026
 * @param {string} response - JSON string returned from Script Include
 * @returns {none}
 */
function poplulateCandidateInformation(response) {
	try {
		// Convert JSON string to object
        var result = JSON.parse(response);

        g_form.setValue('u_candidate_email', result.u_username);
        g_form.setValue('u_candidate_name', result.u_email);
        g_form.setValue('u_candidate_phone', result.u_phone_number);
    } catch (e) {
        g_form.addErrorMessage('Populate candidate information failed');
    }
}
